                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                long loop = (bound_x - i_ker_x)*3;
                i_ker_x = bound_x;
                while(loop > 0)
                {
                    NDS_VEC_VSETVLI(vl, loop, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLB_V(NDS_VEC_V0, pPixel);
                    NDS_VEC_VSB_V(NDS_VEC_V0, pBuffer);
                    pPixel += vl;
                    pBuffer += vl;
                    loop -= vl;
                }

                // if (i_ker_x >= in_tensor_dim)
                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    pBuffer += 3;
                }
            }

            // if (i_ker_y >= in_tensor_dim)
            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, pre_rshift, out_scale, post_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
