    for (; i_out_y < bound_end; i_out_y++)
    {
        /* left part */
        for (i_out_x = 0; i_out_x < bound_begin; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 4 * col_size)
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft_unroll4(ker_weight,
                                                      (q7_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      col_size,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }

        /* mid part — no padding, use bulk copy */
        for (; i_out_x < bound_end; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
                pBuffer += in_tensor_ch * ker_dim;
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 4 * col_size)
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft_unroll4(ker_weight,
                                                      (q7_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      col_size,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }

        /* right part */
        for (; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 4 * col_size)
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft_unroll4(ker_weight,
                                                      (q7_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      col_size,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

