                    {
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                    }
                    else
                    {
                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                    }
                }
