                long inA1, inB1;
                inA1 = *__SIMD32(pA)++;
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }

            colCnt = 3 * ker_dim * ker_dim & 0x3;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

