        q7_t tmp1 = *wt_tmp++;
        q7_t tmp2 = *wt_tmp++;
        *pwt2++ = NDS_DSP_PKBB16(tmp2, tmp1);
        tmp1 = *wt_tmp++;
        *pwt2++ = (u16_t)tmp1;
