// MM_TYPE *nn_mat_mul_kernel_tiling(const MM_TYPE * src1,
//                                   const MM_TYPE * src2,
//                                   MM_TYPE_VQ * tmp_out,
//                                   MM_TYPE * out,
//                                   const uint16_t row,
//                                   const uint16_t col,
//                                   const uint16_t col2,
//                                   const MM_TYPE * bias,
//                                   const uint16_t tiling_size)
