     *   v0-v7  (M8): Accumulator pixel 1 (e32)
     *   v8-v15 (M8): Accumulator pixel 2 (e32)
     *   v16-v17 (M2): Weight vector load (e8)
     */
    const int in_tensor_ch = 3;
    long i_ker_y, i_ker_x, ch;

