        long out_x2 = (pixel_idx + 1) % out_tensor_dim;

        /* Set VL for out_tensor_ch elements at e32 width */
        long vl = __riscv_vsetvl_e32m8(out_tensor_ch);

        /* Load bias into accumulators for both pixels */
        vint32m8_t vAcc1 = __riscv_vle32_v_i32m8(bias, vl);
        vint32m8_t vAcc2 = __riscv_vle32_v_i32m8(bias, vl);

        /* Accumulate over all K positions: ker_y x ker_x x channel */
        for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
        {
            long in_row1 = out_y1 * stride - pad + i_ker_y;
            long in_row2 = out_y2 * stride - pad + i_ker_y;

            for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
            {
                long in_col1 = out_x1 * stride - pad + i_ker_x;
                long in_col2 = out_x2 * stride - pad + i_ker_x;

                /* Weight row index: (ker_y * ker_dim + ker_x) * 3 */
                long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                /* For each of the 3 input channels */
                for (long ch = 0; ch < in_tensor_ch; ch++)
                {
                    long k_pos = k_base + ch;

                    /* Load transposed weight row for this K-position */
                    vl = __riscv_vsetvl_e8m2(out_tensor_ch);
                    vint8m2_t vWt = __riscv_vle8_v_i8m2(src2 + k_pos * out_tensor_ch, vl);

                    /* Get input scalars for pixel 1 */
                    q7_t a1 = 0;
                    if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                        in_col1 >= 0 && in_col1 < in_tensor_dim)
                    {
                        a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                    }

                    /* Get input scalars for pixel 2 */
                    q7_t a2 = 0;
                    if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
                        in_col2 >= 0 && in_col2 < in_tensor_dim)
                    {
                        a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                    }

                    /* Accumulate: acc += input_scalar * weight_vector */
                    vAcc1 = __riscv_vqmacc_vx_i32m8(vAcc1, a1, vWt, vl);
                    vAcc2 = __riscv_vqmacc_vx_i32m8(vAcc2, a2, vWt, vl);
                }
            }
        }

        /* Requantize and store pixel 1 */
        vl = __riscv_vsetvl_e32m8(out_tensor_ch);
        vAcc1 = __riscv_vsra(vAcc1, pre_rshift, vl);
        vAcc1 = __riscv_vmul(vAcc1, out_scale, vl);
        vl = __riscv_vsetvl_e16m4(out_tensor_ch);
        vint16m4_t vResult1_i16 = __riscv_vnclip(vAcc1, post_rshift, __RISCV_VXRM_RNU, vl);
        vl = __riscv_vsetvl_e8m2(out_tensor_ch);
        vint8m2_t vResult1_i8 = __riscv_vnclip(vResult1_i16, 0, __RISCV_VXRM_RNU, vl);
        __riscv_vse8(pOut, vResult1_i8, vl);
        pOut += out_tensor_ch;

        /* Requantize and store pixel 2 */
        vl = __riscv_vsetvl_e32m8(out_tensor_ch);
        vAcc2 = __riscv_vsra(vAcc2, pre_rshift, vl);
        vAcc2 = __riscv_vmul(vAcc2, out_scale, vl);
        vl = __riscv_vsetvl_e16m4(out_tensor_ch);
        vint16m4_t vResult2_i16 = __riscv_vnclip(vAcc2, post_rshift, __RISCV_VXRM_RNU, vl);
        vl = __riscv_vsetvl_e8m2(out_tensor_ch);
        vint8m2_t vResult2_i8 = __riscv_vnclip(vResult2_i16, 0, __RISCV_VXRM_RNU, vl);
        __riscv_vse8(pOut, vResult2_i8, vl);
        pOut += out_tensor_ch;
    }

    /* Handle the last pixel if total_pixels is odd */
    if (pixel_idx < total_pixels)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;

        long vl = __riscv_vsetvl_e32m8(out_tensor_ch);
        vint32m8_t vAcc1 = __riscv_vle32_v_i32m8(bias, vl);

        for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
        {
            long in_row1 = out_y1 * stride - pad + i_ker_y;

            for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
            {
                long in_col1 = out_x1 * stride - pad + i_ker_x;
                long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                for (long ch = 0; ch < in_tensor_ch; ch++)
                {
                    long k_pos = k_base + ch;

                    vl = __riscv_vsetvl_e8m2(out_tensor_ch);
                    vint8m2_t vWt = __riscv_vle8_v_i8m2(src2 + k_pos * out_tensor_ch, vl);

                    q7_t a1 = 0;
                    if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                        in_col1 >= 0 && in_col1 < in_tensor_dim)
                    {
                        a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                    }

                    vAcc1 = __riscv_vqmacc_vx_i32m8(vAcc1, a1, vWt, vl);
                }
            }
        }

        vl = __riscv_vsetvl_e32m8(out_tensor_ch);
        vAcc1 = __riscv_vsra(vAcc1, pre_rshift, vl);
        vAcc1 = __riscv_vmul(vAcc1, out_scale, vl);
        vl = __riscv_vsetvl_e16m4(out_tensor_ch);
        vint16m4_t vResult1_i16 = __riscv_vnclip(vAcc1, post_rshift, __RISCV_VXRM_RNU, vl);
        vl = __riscv_vsetvl_e8m2(out_tensor_ch);
        vint8m2_t vResult1_i8 = __riscv_vnclip(vResult1_i16, 0, __RISCV_VXRM_RNU, vl);
        __riscv_vse8(pOut, vResult1_i8, vl);
        pOut += out_tensor_ch;
    }
#else /* NDS_VEC_RVV_VERSION < 1000: fallback to tiling GEMM */

toolUseResult.newString:
#ifdef ENA_TILING
#if (NDS_VEC_RVV_VERSION >= 1000)
    /*
     * Direct convolution with fused bias + requantize.
     * Vectorizes across out_tensor_ch: vqmacc.vx accumulates one input scalar
     * against the full transposed weight row (all output channels).
     * Processes 2 output pixels at a time, sharing weight loads.
     * Eliminates im2col buffer and q32 intermediate buffer.
     *
     * Register plan:
     *   v0-v7  (M8): Accumulator pixel 1 (e32)
     *   v8-v15 (M8): Accumulator pixel 2 (e32)
     *   v16-v17 (M2): Weight vector load (e8)
     */
    const int in_tensor_ch = 3;
    long i_ker_y, i_ker_x, ch;

    const long align_byte = 64;
    q7_t *pOut = out_tensor;
    long vl;

    /* Allocate transposed weight buffer from in_tmp_buf */
    q7_t *src2 = (q7_t *)in_tmp_buf;
    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);

    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
    const long row = out_tensor_ch;
    const long col = ker_dim * ker_dim * in_tensor_ch;
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

    /* Total output pixels */
    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
    long pixel_idx = 0;

    /* Process 2 output pixels at a time */
    for (; pixel_idx + 1 < total_pixels; pixel_idx += 2)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;
        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
        long out_x2 = (pixel_idx + 1) % out_tensor_dim;

        /* Load bias into accumulators: v0 (pixel1), v8 (pixel2) at e32/M8 */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, bias);
        NDS_VEC_VLE32_V(NDS_VEC_V8, bias);

        /* Accumulate over all K positions */
        for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
        {
            long in_row1 = out_y1 * stride - pad + i_ker_y;
            long in_row2 = out_y2 * stride - pad + i_ker_y;

            for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
            {
                long in_col1 = out_x1 * stride - pad + i_ker_x;
                long in_col2 = out_x2 * stride - pad + i_ker_x;
                long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                for (ch = 0; ch < in_tensor_ch; ch++)
                {
                    long k_pos = k_base + ch;

                    /* Load transposed weight row into v16 at e8/M2 */
                    NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);

                    /* Get input scalars */
                    q7_t a1 = 0, a2 = 0;
                    if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                        in_col1 >= 0 && in_col1 < in_tensor_dim)
                        a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                    if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
                        in_col2 >= 0 && in_col2 < in_tensor_dim)
                        a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];

                    /* vqmacc.vx: acc[e32/M8] += scalar * wt[e8/M2] */
                    NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                    NDS_VEC_VQMACC_VX(NDS_VEC_V8, a2, NDS_VEC_V16);
                }
            }
        }

        /* Requantize pixel 1: shift, scale, narrow, clip, store */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
        pOut += out_tensor_ch;

        /* Requantize pixel 2 */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, 0);
        NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
        pOut += out_tensor_ch;
    }

    /* Handle the last pixel if total_pixels is odd */
    if (pixel_idx < total_pixels)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;

        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, bias);

        for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
        {
            long in_row1 = out_y1 * stride - pad + i_ker_y;
            for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
            {
                long in_col1 = out_x1 * stride - pad + i_ker_x;
                long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                for (ch = 0; ch < in_tensor_ch; ch++)
                {
                    long k_pos = k_base + ch;
                    NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);
                    q7_t a1 = 0;
                    if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                        in_col1 >= 0 && in_col1 < in_tensor_dim)
                        a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                    NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                }
            }
        }

        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
        pOut += out_tensor_ch;
    }
#else /* NDS_VEC_RVV_VERSION < 1000: fallback to tiling GEMM */

