        vint8m2_t vResult1_i8 = __riscv_vnclip(vResult1_i16, 0, __RISCV_VXRM_RNU, vl);
        __riscv_vse8(pOut, vResult1_i8, vl);
        pOut += out_tensor_ch;
    }
#else /* NDS_VEC_RVV_VERSION < 1000: fallback to tiling GEMM */
    //cache is 512KB, type is q7
    uint32_t tiling_size = 256;
