            NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);   //zero
            while(len > 0)
            {
                NDS_VEC_VSB_V(NDS_VEC_V24, pBuffer2);
                len -= vl;
                pBuffer2 += vl;
                NDS_VEC_VSETVLI(vl, len, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            }

            // if (i_ker_y < 0)
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
